mapper.select:
 /* NaverPlacePlusLinkMapper.getNaverStore */
SELECT  NAVER_STORE_NM
,       NAVER_PLACE_ID
,       NAVER_LINK_DT
FROM    TB_CM_NAVER_LINK
WHERE   HQ_OFFICE_CD = #{hqOfficeCd}
AND     STORE_CD = #{storeCd}

 /* NaverPlacePlusLinkMapper.getNaverUniqueId */
SELECT  UNIQUE_ID
FROM    TB_CM_NAVER_LINK
WHERE   HQ_OFFICE_CD = #{hqOfficeCd}
AND     STORE_CD = #{storeCd}

mapper.update:
/* NaverPlacePlusLinkMapper.updateNaverStore */
UPDATE TB_CM_NAVER_LINK
SET    NAVER_STORE_NM = #{naverStoreNm}
,      NAVER_PLACE_ID = #{naverPlaceId}
,      NAVER_LINK_DT = #{naverLinkDt}
,      MOD_DT = #{modDt}
,      MOD_ID = #{modId}
WHERE  1=1


        AND   UNIQUE_ID = #{uniqueId}
        AND   STORE_CD = #{storeCd}


        AND   HQ_OFFICE_CD = #{hqOfficeCd}
        AND   STORE_CD = #{storeCd}

